function firstName(name) {
  return String(name || 'cliente').trim().split(/\s+/)[0] || 'cliente';
}
const data = $json;
const ctx = data.context || {};
const nome = firstName(data.customer_name);
const link = ctx.link_renovacao || ctx.link_pagamento || ctx.link_checkout || ctx.link_nova_emissao || null;
let reply = '';
if (data.intent === 'seguir_renovacao') {
  reply = link
    ? 'Olá, ' + nome + '. Vamos continuar sua renovação por aqui. Segue novamente o link para avançar: ' + link
    : 'Olá, ' + nome + '. Recebi seu retorno sobre a renovação. Vou seguir com você por aqui e, se precisar, envio novamente o link de continuidade.';
} else if (data.intent === 'enviar_documentos') {
  reply = 'Olá, ' + nome + '. Pode me enviar os documentos por este canal. Assim que eu receber, sigo com sua renovação e te atualizo aqui.';
} else {
  reply = link
    ? 'Olá, ' + nome + '. Estou seguindo seu atendimento de renovação. Se quiser, já pode usar este link: ' + link
    : 'Olá, ' + nome + '. Estou seguindo seu atendimento de renovação por aqui. Se precisar de link ou orientação, eu te envio na sequência.';
}
return [{ json: { ...data, reply_text: reply, reply_subject: 'Continuidade da renovacao', event_type: 'automation.trigger', entity_type: 'renovacoes' } }];
